class Solution {
    public long validSubstringCount(String word1, String word2) {
        int n = word1.length(), m = word2.length();
        if (n < m) return 0;

        int[] need = new int[26];
        for (char c : word2.toCharArray()) need[c - 'a']++;

        int[] freq = new int[26];
        long res = 0;
        int left = 0, deficit = 0;

        for (int i = 0; i < 26; i++) if (need[i] > 0) deficit++;

        for (int right = 0; right < n; right++) {
            int c = word1.charAt(right) - 'a';
            freq[c]++;
            if (freq[c] == need[c]) deficit--;

            while (right - left + 1 >= m && deficit == 0) {
                if (right - left + 1 >= m) {
                    res += n - right;
                }
                int leftC = word1.charAt(left) - 'a';
                if (freq[leftC] == need[leftC]) deficit++;
                freq[leftC]--;
                left++;
            }
        }
        return res;
    }
}
